        try {
            const params = { 
                page, 
                size,
                sort: 'createdAt,desc'
            };
            const response = await api.get('/purchases/orders', { params });
            return response.data;
        } catch (error) {
            console.error('Error fetching purchase orders:', error);
            throw error;
        }
    },

    /**
     * Get purchase orders by supplier
