     */
    convertOrderToInvoice: async (id) => {
        try {
            const response = await api.put(`/purchases/order/${id}/convert`);
            return response.data;
        } catch (error) {
            console.error(`Error converting purchase order ${id} to invoice:`, error);
            throw error;
        }
    },

    /**
     * Delete purchase order
     */
    deleteOrder: async (id) => {
        try {
            const response = await api.delete(`/purchases/order/${id}`);
            return response.data;
        } catch (error) {
            console.error(`Error deleting purchase order with ID ${id}:`, error);
            throw error;
        }
    },

    // ==================== PURCHASE INVOICE METHODS ====================

    /**
     * Create a new purchase invoice
     */
    createInvoice: async (data) => {
        try {
            const response = await api.post('/purchases/invoice', data);
            return response.data;
        } catch (error) {
            console.error('Error creating purchase invoice:', error);
            throw error;
        }
    },

    /**
     * Get purchase invoice by invoice number
