     */
    search: async (search, page = 0, size = 20) => {
        try {
            const response = await api.get('/purchases/invoices/search', {
                params: { search, page, size },
            });
            return response.data;
        } catch (error) {
            console.error(`Error searching purchase invoices with term "${search}":`, error);
            throw error;
        }
    },

    // ==================== PURCHASE RETURN METHODS ====================

    /**
     * Create a purchase return
     */
    createReturn: async (data) => {
        try {
            const response = await api.post('/purchases/return', data);
            return response.data;
        } catch (error) {
            console.error('Error creating purchase return:', error);
            throw error;
        }
    },

    /**
