     */
    getReturnByNo: async (returnNo) => {
        try {
            const response = await api.get(`/purchases/return/${returnNo}`);
            return response.data;
        } catch (error) {
            console.error(`Error fetching purchase return with return number ${returnNo}:`, error);
            throw error;
        }
    },

    /**
