     */
    getReturnsByInvoice: async (invoiceNo) => {
        try {
            const response = await api.get(`/purchases/returns/invoice/${invoiceNo}`);
            return response.data;
        } catch (error) {
            console.error(`Error fetching purchase returns for invoice ${invoiceNo}:`, error);
            throw error;
        }
